"use client";

import React from "react";
import {
    DndContext,
    closestCenter,
    KeyboardSensor,
    PointerSensor,
    useSensor,
    useSensors,
    DragEndEvent,
} from "@dnd-kit/core";
import {
    arrayMove,
    SortableContext,
    sortableKeyboardCoordinates,
    verticalListSortingStrategy,
} from "@dnd-kit/sortable";
import { restrictToVerticalAxis } from "@dnd-kit/modifiers";

export interface SortableListProps {
    items: { id: string }[];
    onReorder: (newItems: any[]) => void;
    children: React.ReactNode;
}

export function SortableList({ items, onReorder, children }: SortableListProps) {
    const sensors = useSensors(
        useSensor(PointerSensor, {
            activationConstraint: {
                distance: 5, // 5px movement required before drag starts, allows clicking inner buttons
            },
        }),
        useSensor(KeyboardSensor, {
            coordinateGetter: sortableKeyboardCoordinates,
        })
    );

    function handleDragEnd(event: DragEndEvent) {
        const { active, over } = event;

        if (over && active.id !== over.id) {
            const oldIndex = items.findIndex((i) => i.id === active.id);
            const newIndex = items.findIndex((i) => i.id === over.id);
            onReorder(arrayMove(items, oldIndex, newIndex));
        }
    }

    return (
        <DndContext
            sensors={sensors}
            collisionDetection={closestCenter}
            onDragEnd={handleDragEnd}
            modifiers={[restrictToVerticalAxis]}
        >
            <SortableContext
                items={items.map((i) => i.id)}
                strategy={verticalListSortingStrategy}
            >
                {children}
            </SortableContext>
        </DndContext>
    );
}

"use client";

import React from "react";
import { TemplateProps } from "./ClassicTemplate";
import { SortableList } from "../dnd/SortableList";
import { SortableItem } from "../dnd/SortableItem";
import { useCVStore } from "@/lib/cv-store";

function EditableText({
    value, path, onFieldChange, style, tag: Tag = "span",
}: { value: string; path: string; onFieldChange: (p: string, v: string) => void; style?: React.CSSProperties; tag?: keyof React.JSX.IntrinsicElements; }) {
    return (
        <Tag
            contentEditable suppressContentEditableWarning
            onBlur={(e) => onFieldChange(path, (e.currentTarget as HTMLElement).innerText.trim())}
            style={{ outline: "none", cursor: "text", borderRadius: 3, minWidth: 20, ...style }}
            className="editable-field"
        >{value}</Tag>
    );
}

export default function CompactTemplate({ cv, onFieldChange }: TemplateProps) {
    const { dispatch } = useCVStore();
    const accent = cv.layout?.themeColor || "#8b5cf6";

    const sectionComponents: Record<string, React.ReactNode> = {
        summary: cv.summary && (
            <div style={{ marginBottom: 16 }}>
                <CmpSection title="Summary" accent={accent} />
                <EditableText value={cv.summary} path="summary" onFieldChange={onFieldChange} tag="p"
                    style={{ fontSize: "0.78rem", color: "#374151", lineHeight: 1.6 }} />
            </div>
        ),
        experience: cv.experience.length > 0 && (
            <div style={{ marginBottom: 16 }}>
                <CmpSection title="Experience" accent={accent} />
                <SortableList
                    items={cv.experience}
                    onReorder={(newOrder: any[]) => {
                        dispatch({ type: "REORDER_LIST", payload: { path: "experience", newOrder } });
                    }}
                >
                    {cv.experience.map((exp, ei) => (
                        <SortableItem key={exp.id} id={exp.id} handleStyle={{ top: 0, left: -24 }}>
                            <div style={{ marginBottom: 12 }}>
                                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline" }}>
                                    <EditableText value={exp.jobTitle} path={`experience.${ei}.jobTitle`} onFieldChange={onFieldChange} tag="h3"
                                        style={{ fontSize: "0.8125rem", fontWeight: 700, color: "#1a1a2e" }} />
                                    <span style={{ fontSize: "0.68rem", color: "#9ca3af", flexShrink: 0, marginLeft: 6 }}>
                                        <EditableText value={exp.startDate} path={`experience.${ei}.startDate`} onFieldChange={onFieldChange} />–<EditableText value={exp.endDate} path={`experience.${ei}.endDate`} onFieldChange={onFieldChange} />
                                    </span>
                                </div>
                                <div style={{ fontSize: "0.75rem", color: accent, fontWeight: 500, marginBottom: 3 }}>
                                    <EditableText value={exp.company} path={`experience.${ei}.company`} onFieldChange={onFieldChange} />
                                    {exp.location && <span style={{ color: "#9ca3af", fontWeight: 400 }}> · <EditableText value={exp.location} path={`experience.${ei}.location`} onFieldChange={onFieldChange} /></span>}
                                </div>
                                {exp.description.map((d, di) => (
                                    <div key={di} style={{ fontSize: "0.76rem", color: "#374151", lineHeight: 1.5, marginBottom: 1 }}>
                                        · <EditableText value={d} path={`experience.${ei}.description.${di}`} onFieldChange={onFieldChange} />
                                    </div>
                                ))}
                            </div>
                        </SortableItem>
                    ))}
                </SortableList>
            </div>
        ),
        education: cv.education.length > 0 && (
            <div style={{ marginBottom: 16 }}>
                <CmpSection title="Education" accent={accent} />
                <SortableList
                    items={cv.education}
                    onReorder={(newOrder: any[]) => {
                        dispatch({ type: "REORDER_LIST", payload: { path: "education", newOrder } });
                    }}
                >
                    {cv.education.map((edu, ei) => (
                        <SortableItem key={edu.id} id={edu.id} handleStyle={{ top: 0, left: -24 }}>
                            <div style={{ marginBottom: 8, display: "flex", justifyContent: "space-between" }}>
                                <div>
                                    <EditableText value={edu.degree} path={`education.${ei}.degree`} onFieldChange={onFieldChange} tag="h3"
                                        style={{ fontSize: "0.8125rem", fontWeight: 700, color: "#1a1a2e" }} />
                                    <div style={{ fontSize: "0.75rem", color: accent, fontWeight: 500 }}>
                                        <EditableText value={edu.institution} path={`education.${ei}.institution`} onFieldChange={onFieldChange} />
                                    </div>
                                </div>
                                <div style={{ fontSize: "0.72rem", color: "#9ca3af", textAlign: "right" }}>
                                    <EditableText value={edu.startDate} path={`education.${ei}.startDate`} onFieldChange={onFieldChange} />–<EditableText value={edu.endDate} path={`education.${ei}.endDate`} onFieldChange={onFieldChange} />
                                    {edu.gpa && <div>GPA <EditableText value={edu.gpa} path={`education.${ei}.gpa`} onFieldChange={onFieldChange} /></div>}
                                </div>
                            </div>
                        </SortableItem>
                    ))}
                </SortableList>
            </div>
        ),
        skills: cv.skills.length > 0 && (
            <div style={{ marginBottom: 16 }}>
                <CmpSection title="Skills" accent={accent} />
                <div style={{ display: "flex", flexWrap: "wrap", gap: 4 }}>
                    {cv.skills.map((skill, i) => (
                        <span key={i} style={{ fontSize: "0.7rem", padding: "2px 8px", background: "#ede9fe", color: "#5b21b6", borderRadius: 12, fontWeight: 500 }}>
                            <EditableText value={skill} path={`skills.${i}`} onFieldChange={onFieldChange} />
                        </span>
                    ))}
                </div>
            </div>
        ),
        languages: cv.languages && cv.languages.length > 0 && (
            <div style={{ marginBottom: 16 }}>
                <CmpSection title="Languages" accent={accent} />
                <div style={{ fontSize: "0.76rem", color: "#374151" }}>
                    {cv.languages.map((lang, i) => (
                        <React.Fragment key={i}>
                            <EditableText value={lang} path={`languages.${i}`} onFieldChange={onFieldChange} />
                            {i < (cv.languages?.length ?? 0) - 1 && <span style={{ color: "#d1d5db" }}> · </span>}
                        </React.Fragment>
                    ))}
                </div>
            </div>
        ),
        certifications: cv.certifications && cv.certifications.length > 0 && (
            <div style={{ marginBottom: 16 }}>
                <CmpSection title="Certifications" accent={accent} />
                {cv.certifications.map((cert, i) => (
                    <div key={i} style={{ fontSize: "0.76rem", color: "#374151", lineHeight: 1.5, marginBottom: 2 }}>
                        · <EditableText value={cert} path={`certifications.${i}`} onFieldChange={onFieldChange} />
                    </div>
                ))}
            </div>
        )
    };

    const sectionOrderItems = (cv.layout?.sectionOrder || ["summary", "experience", "education", "skills", "languages", "certifications"]).map((id) => {
        if (!sectionComponents[id]) return null;
        return { id };
    }).filter(Boolean) as { id: string }[];

    return (
        <div style={{ fontFamily: "'Inter', sans-serif", color: "#1a1a2e", background: "white", fontSize: "0.8rem", padding: "0 20px" }}>
            {/* Header */}
            {cv.personalInfo.fullName && (
                <div style={{ marginBottom: 20, borderBottom: `2px solid ${accent}`, paddingBottom: 10, paddingTop: 20 }}>
                    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-end" }}>
                        <div>
                            <EditableText value={cv.personalInfo.fullName} path="personalInfo.fullName" onFieldChange={onFieldChange} tag="h1"
                                style={{ fontSize: "1.5rem", fontWeight: 800, color: "#1a1a2e", letterSpacing: "-0.03em", display: "block", marginBottom: 2 }} />
                            {cv.personalInfo.title && (
                                <EditableText value={cv.personalInfo.title} path="personalInfo.title" onFieldChange={onFieldChange} tag="div"
                                    style={{ fontSize: "0.8125rem", color: accent, fontWeight: 600 }} />
                            )}
                        </div>
                        <div style={{ textAlign: "right", fontSize: "0.72rem", color: "#9ca3af", display: "flex", flexDirection: "column", gap: 2 }}>
                            {cv.personalInfo.email && <EditableText value={cv.personalInfo.email} path="personalInfo.email" onFieldChange={onFieldChange} tag="div" />}
                            {cv.personalInfo.phone && <EditableText value={cv.personalInfo.phone} path="personalInfo.phone" onFieldChange={onFieldChange} tag="div" />}
                            {cv.personalInfo.location && <EditableText value={cv.personalInfo.location} path="personalInfo.location" onFieldChange={onFieldChange} tag="div" />}
                            {cv.personalInfo.linkedin && <EditableText value={cv.personalInfo.linkedin} path="personalInfo.linkedin" onFieldChange={onFieldChange} tag="div" />}
                        </div>
                    </div>
                </div>
            )}

            <div style={{ paddingBottom: 30 }}>
                <SortableList
                    items={sectionOrderItems}
                    onReorder={(newOrder: any[]) => {
                        dispatch({ type: "REORDER_SECTIONS", payload: newOrder.map((o: any) => o.id) });
                    }}
                >
                    {sectionOrderItems.map((item) => (
                        <SortableItem key={item.id} id={item.id}>
                            {sectionComponents[item.id]}
                        </SortableItem>
                    ))}
                </SortableList>
            </div>
        </div>
    );
}

function CmpSection({ title, accent }: { title: string; accent: string }) {
    return (
        <h2 style={{ fontSize: "0.7rem", fontWeight: 700, textTransform: "uppercase", letterSpacing: "0.12em", color: accent, borderBottom: `1.5px solid ${accent}`, paddingBottom: 3, marginBottom: 8 }}>
            {title}
        </h2>
    );
}

"use client";

import React from "react";
import { TemplateProps } from "./ClassicTemplate";
import { SortableList } from "../dnd/SortableList";
import { SortableItem } from "../dnd/SortableItem";
import { useCVStore } from "@/lib/cv-store";

function EditableText({
    value, path, onFieldChange, style, tag: Tag = "span",
}: { value: string; path: string; onFieldChange: (p: string, v: string) => void; style?: React.CSSProperties; tag?: keyof React.JSX.IntrinsicElements; }) {
    return (
        <Tag
            contentEditable suppressContentEditableWarning
            onBlur={(e) => onFieldChange(path, (e.currentTarget as HTMLElement).innerText.trim())}
            style={{ outline: "none", cursor: "text", borderRadius: 3, minWidth: 20, ...style }}
            className="editable-field"
        >{value}</Tag>
    );
}

export default function CreativeTemplate({ cv, onFieldChange }: TemplateProps) {
    const { dispatch } = useCVStore();
    const accent = cv.layout?.themeColor || "#f59e0b";
    const accent2 = "#ef4444";

    const sectionComponents: Record<string, React.ReactNode> = {
        summary: cv.summary && (
            <div style={{ marginBottom: 24 }}>
                <CreSection title="About Me" accent={accent} />
                <EditableText value={cv.summary} path="summary" onFieldChange={onFieldChange} tag="p"
                    style={{ fontSize: "0.8125rem", color: "#374151", lineHeight: 1.75 }} />
            </div>
        ),
        experience: cv.experience.length > 0 && (
            <div style={{ marginBottom: 24 }}>
                <CreSection title="Experience" accent={accent} />
                <SortableList
                    items={cv.experience}
                    onReorder={(newOrder: any[]) => {
                        dispatch({ type: "REORDER_LIST", payload: { path: "experience", newOrder } });
                    }}
                >
                    {cv.experience.map((exp, ei) => (
                        <SortableItem key={exp.id} id={exp.id} handleStyle={{ top: 0, left: -24 }}>
                            <div style={{ marginBottom: 18, display: "flex", gap: 14 }}>
                                {/* Timeline dot */}
                                <div style={{ display: "flex", flexDirection: "column", alignItems: "center", flexShrink: 0 }}>
                                    <div style={{ width: 10, height: 10, borderRadius: "50%", background: `linear-gradient(135deg, ${accent}, ${accent2})`, marginTop: 4 }} />
                                    {ei < cv.experience.length - 1 && <div style={{ width: 2, flex: 1, background: "#fde68a", marginTop: 4 }} />}
                                </div>
                                <div style={{ flex: 1 }}>
                                    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: 1 }}>
                                        <EditableText value={exp.jobTitle} path={`experience.${ei}.jobTitle`} onFieldChange={onFieldChange} tag="h3"
                                            style={{ fontSize: "0.9375rem", fontWeight: 700, color: "#1a1a2e" }} />
                                        <span style={{ fontSize: "0.72rem", color: "#9ca3af", flexShrink: 0, marginLeft: 8 }}>
                                            <EditableText value={exp.startDate} path={`experience.${ei}.startDate`} onFieldChange={onFieldChange} /> — <EditableText value={exp.endDate} path={`experience.${ei}.endDate`} onFieldChange={onFieldChange} />
                                        </span>
                                    </div>
                                    <div style={{ fontSize: "0.8rem", color: accent, fontWeight: 600, marginBottom: 5 }}>
                                        <EditableText value={exp.company} path={`experience.${ei}.company`} onFieldChange={onFieldChange} />
                                        {exp.location && <span style={{ color: "#9ca3af", fontWeight: 400 }}> · <EditableText value={exp.location} path={`experience.${ei}.location`} onFieldChange={onFieldChange} /></span>}
                                    </div>
                                    {exp.description.map((d, di) => (
                                        <div key={di} style={{ fontSize: "0.8rem", color: "#374151", lineHeight: 1.6, marginBottom: 2 }}>
                                            → <EditableText value={d} path={`experience.${ei}.description.${di}`} onFieldChange={onFieldChange} />
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </SortableItem>
                    ))}
                </SortableList>
            </div>
        ),
        education: cv.education.length > 0 && (
            <div style={{ marginBottom: 24 }}>
                <CreSection title="Education" accent={accent} />
                <SortableList
                    items={cv.education}
                    onReorder={(newOrder: any[]) => {
                        dispatch({ type: "REORDER_LIST", payload: { path: "education", newOrder } });
                    }}
                >
                    {cv.education.map((edu, ei) => (
                        <SortableItem key={edu.id} id={edu.id} handleStyle={{ top: 0, left: -24 }}>
                            <div style={{ marginBottom: 12, display: "flex", gap: 14 }}>
                                <div style={{ display: "flex", flexDirection: "column", alignItems: "center", flexShrink: 0 }}>
                                    <div style={{ width: 10, height: 10, borderRadius: "50%", border: `2px solid ${accent}`, background: "white", marginTop: 4 }} />
                                </div>
                                <div style={{ flex: 1 }}>
                                    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline" }}>
                                        <EditableText value={edu.degree} path={`education.${ei}.degree`} onFieldChange={onFieldChange} tag="h3"
                                            style={{ fontSize: "0.9375rem", fontWeight: 700, color: "#1a1a2e" }} />
                                        <span style={{ fontSize: "0.72rem", color: "#9ca3af", flexShrink: 0, marginLeft: 8 }}>
                                            <EditableText value={edu.startDate} path={`education.${ei}.startDate`} onFieldChange={onFieldChange} /> — <EditableText value={edu.endDate} path={`education.${ei}.endDate`} onFieldChange={onFieldChange} />
                                        </span>
                                    </div>
                                    <div style={{ fontSize: "0.8rem", color: "#6b7280" }}>
                                        <EditableText value={edu.institution} path={`education.${ei}.institution`} onFieldChange={onFieldChange} />
                                        {edu.location && <span> · <EditableText value={edu.location} path={`education.${ei}.location`} onFieldChange={onFieldChange} /></span>}
                                    </div>
                                </div>
                            </div>
                        </SortableItem>
                    ))}
                </SortableList>
            </div>
        ),
        skills: cv.skills.length > 0 && (
            <div style={{ marginBottom: 22 }}>
                <CreSection title="Skills" accent={accent} />
                <div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>
                    {cv.skills.map((skill, i) => {
                        const colours = ["#fef3c7", "#fee2e2", "#fce7f3", "#dbeafe", "#ecfdf5", "#ede9fe"];
                        const textColours = ["#92400e", "#991b1b", "#9d174d", "#1e40af", "#065f46", "#5b21b6"];
                        const ci = i % colours.length;
                        return (
                            <span key={i} style={{ fontSize: "0.75rem", padding: "4px 12px", background: colours[ci], color: textColours[ci], borderRadius: 20, fontWeight: 500 }}>
                                <EditableText value={skill} path={`skills.${i}`} onFieldChange={onFieldChange} />
                            </span>
                        );
                    })}
                </div>
            </div>
        ),
        languages: cv.languages && cv.languages.length > 0 && (
            <div style={{ marginBottom: 22 }}>
                <CreSection title="Languages" accent={accent} />
                <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
                    {cv.languages.map((lang, i) => (
                        <span key={i} style={{ fontSize: "0.75rem", padding: "4px 12px", background: "#fef3c7", color: "#92400e", borderRadius: 20, fontWeight: 500 }}>
                            <EditableText value={lang} path={`languages.${i}`} onFieldChange={onFieldChange} />
                        </span>
                    ))}
                </div>
            </div>
        ),
        certifications: cv.certifications && cv.certifications.length > 0 && (
            <div style={{ marginBottom: 22 }}>
                <CreSection title="Certifications" accent={accent} />
                <ul style={{ paddingLeft: 16, listStyleType: "none", margin: 0 }}>
                    {cv.certifications.map((cert, i) => (
                        <li key={i} style={{ fontSize: "0.8125rem", color: "#374151", lineHeight: 1.6, marginBottom: 4 }}>
                            ✦ <EditableText value={cert} path={`certifications.${i}`} onFieldChange={onFieldChange} />
                        </li>
                    ))}
                </ul>
            </div>
        )
    };

    const sectionOrderItems = (cv.layout?.sectionOrder || ["summary", "experience", "education", "skills", "languages", "certifications"]).map((id) => {
        if (!sectionComponents[id]) return null;
        return { id };
    }).filter(Boolean) as { id: string }[];

    return (
        <div style={{ fontFamily: "'Inter', sans-serif", color: "#1a1a2e", background: "white", display: "flex", flex: 1 }}>
            {/* Left colour strip */}
            <div style={{ width: 6, background: `linear-gradient(180deg, ${accent}, ${accent2})`, borderRadius: "4px 0 0 4px", flexShrink: 0 }} />

            <div style={{ flex: 1, padding: "36px 36px 36px 30px" }}>
                {/* Header */}
                {cv.personalInfo.fullName && (
                    <div style={{ marginBottom: 26, paddingBottom: 18, borderBottom: `2px dashed #fde68a` }}>
                        <EditableText value={cv.personalInfo.fullName} path="personalInfo.fullName" onFieldChange={onFieldChange} tag="h1"
                            style={{ fontSize: "2rem", fontWeight: 900, color: "#1a1a2e", letterSpacing: "-0.04em", marginBottom: 6, display: "block" }} />
                        {cv.personalInfo.title && (
                            <div style={{ display: "inline-flex" }}>
                                <EditableText value={cv.personalInfo.title} path="personalInfo.title" onFieldChange={onFieldChange} tag="span"
                                    style={{
                                        fontSize: "0.875rem", fontWeight: 600, marginBottom: 12,
                                        background: `linear-gradient(135deg, ${accent}, ${accent2})`,
                                        WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent",
                                    }} />
                            </div>
                        )}
                        <div style={{ display: "flex", flexWrap: "wrap", gap: "5px 14px", fontSize: "0.775rem", color: "#9ca3af", marginTop: 6 }}>
                            {cv.personalInfo.email && <EditableText value={cv.personalInfo.email} path="personalInfo.email" onFieldChange={onFieldChange} />}
                            {cv.personalInfo.phone && <EditableText value={cv.personalInfo.phone} path="personalInfo.phone" onFieldChange={onFieldChange} />}
                            {cv.personalInfo.location && <EditableText value={cv.personalInfo.location} path="personalInfo.location" onFieldChange={onFieldChange} />}
                            {cv.personalInfo.linkedin && <EditableText value={cv.personalInfo.linkedin} path="personalInfo.linkedin" onFieldChange={onFieldChange} />}
                        </div>
                    </div>
                )}

                <SortableList
                    items={sectionOrderItems}
                    onReorder={(newOrder: any[]) => {
                        dispatch({ type: "REORDER_SECTIONS", payload: newOrder.map((o: any) => o.id) });
                    }}
                >
                    {sectionOrderItems.map((item) => (
                        <SortableItem key={item.id} id={item.id}>
                            {sectionComponents[item.id]}
                        </SortableItem>
                    ))}
                </SortableList>
            </div>
        </div>
    );
}

function CreSection({ title, accent }: { title: string; accent: string }) {
    return (
        <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 12 }}>
            <div style={{ width: 18, height: 2, background: accent, borderRadius: 1 }} />
            <h2 style={{ fontSize: "0.8125rem", fontWeight: 800, textTransform: "uppercase", letterSpacing: "0.12em", color: "#1a1a2e" }}>
                {title}
            </h2>
        </div>
    );
}

"use client";

import React from "react";
import { TemplateProps } from "./ClassicTemplate";
import { SortableList } from "../dnd/SortableList";
import { SortableItem } from "../dnd/SortableItem";
import { useCVStore } from "@/lib/cv-store";

function EditableText({
    value, path, onFieldChange, style, tag: Tag = "span",
}: { value: string; path: string; onFieldChange: (p: string, v: string) => void; style?: React.CSSProperties; tag?: keyof React.JSX.IntrinsicElements; }) {
    return (
        <Tag
            contentEditable suppressContentEditableWarning
            onBlur={(e) => onFieldChange(path, (e.currentTarget as HTMLElement).innerText.trim())}
            style={{ outline: "none", cursor: "text", borderRadius: 3, minWidth: 20, ...style }}
            className="editable-field"
        >{value}</Tag>
    );
}

export default function ExecutiveTemplate({ cv, onFieldChange }: TemplateProps) {
    const { dispatch } = useCVStore();
    const accent = cv.layout?.themeColor || "#0ea5e9";
    const headerBg = "#0f172a";

    const sectionComponents: Record<string, React.ReactNode> = {
        summary: cv.summary && (
            <div style={{ marginBottom: 26 }}>
                <ExecSection title="Executive Summary" accent={accent} />
                <div style={{ background: "#f8fafc", borderLeft: `4px solid ${accent}`, padding: "14px 18px", borderRadius: "0 8px 8px 0" }}>
                    <EditableText value={cv.summary} path="summary" onFieldChange={onFieldChange} tag="p"
                        style={{ fontSize: "0.875rem", color: "#334155", lineHeight: 1.75, fontStyle: "italic" }} />
                </div>
            </div>
        ),
        experience: cv.experience.length > 0 && (
            <div style={{ marginBottom: 26 }}>
                <ExecSection title="Professional Experience" accent={accent} />
                <SortableList
                    items={cv.experience}
                    onReorder={(newOrder: any[]) => {
                        dispatch({ type: "REORDER_LIST", payload: { path: "experience", newOrder } });
                    }}
                >
                    {cv.experience.map((exp, ei) => (
                        <SortableItem key={exp.id} id={exp.id} handleStyle={{ top: 0, left: -28 }}>
                            <div style={{ marginBottom: 20 }}>
                                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 2 }}>
                                    <div>
                                        <EditableText value={exp.jobTitle} path={`experience.${ei}.jobTitle`} onFieldChange={onFieldChange} tag="h3"
                                            style={{ fontSize: "1rem", fontWeight: 800, color: "#0f172a" }} />
                                        <div style={{ fontSize: "0.8125rem", color: accent, fontWeight: 600 }}>
                                            <EditableText value={exp.company} path={`experience.${ei}.company`} onFieldChange={onFieldChange} />
                                            {exp.location && <span style={{ color: "#94a3b8", fontWeight: 400 }}> · <EditableText value={exp.location} path={`experience.${ei}.location`} onFieldChange={onFieldChange} /></span>}
                                        </div>
                                    </div>
                                    <div style={{ background: "#f1f5f9", borderRadius: 6, padding: "3px 10px", fontSize: "0.75rem", color: "#64748b", fontWeight: 600, flexShrink: 0, marginLeft: 12 }}>
                                        <EditableText value={exp.startDate} path={`experience.${ei}.startDate`} onFieldChange={onFieldChange} /> — <EditableText value={exp.endDate} path={`experience.${ei}.endDate`} onFieldChange={onFieldChange} />
                                    </div>
                                </div>
                                {exp.description.length > 0 && (
                                    <ul style={{ paddingLeft: 18, listStyleType: "disc", marginTop: 6 }}>
                                        {exp.description.map((d, di) => (
                                            <li key={di} style={{ fontSize: "0.8125rem", color: "#475569", lineHeight: 1.65, marginBottom: 3 }}>
                                                <EditableText value={d} path={`experience.${ei}.description.${di}`} onFieldChange={onFieldChange} />
                                            </li>
                                        ))}
                                    </ul>
                                )}
                            </div>
                        </SortableItem>
                    ))}
                </SortableList>
            </div>
        ),
        education: cv.education.length > 0 && (
            <div style={{ marginBottom: 26 }}>
                <ExecSection title="Education" accent={accent} />
                <SortableList
                    items={cv.education}
                    onReorder={(newOrder: any[]) => {
                        dispatch({ type: "REORDER_LIST", payload: { path: "education", newOrder } });
                    }}
                >
                    {cv.education.map((edu, ei) => (
                        <SortableItem key={edu.id} id={edu.id} handleStyle={{ top: 0, left: -28 }}>
                            <div style={{ marginBottom: 14, display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
                                <div>
                                    <EditableText value={edu.degree} path={`education.${ei}.degree`} onFieldChange={onFieldChange} tag="h3"
                                        style={{ fontSize: "0.9375rem", fontWeight: 700, color: "#0f172a" }} />
                                    <div style={{ fontSize: "0.8125rem", color: accent, fontWeight: 500 }}>
                                        <EditableText value={edu.institution} path={`education.${ei}.institution`} onFieldChange={onFieldChange} />
                                        {edu.location && <span style={{ color: "#94a3b8", fontWeight: 400 }}> · <EditableText value={edu.location} path={`education.${ei}.location`} onFieldChange={onFieldChange} /></span>}
                                    </div>
                                    {edu.gpa && <div style={{ fontSize: "0.8rem", color: "#94a3b8", marginTop: 2 }}>GPA: <EditableText value={edu.gpa} path={`education.${ei}.gpa`} onFieldChange={onFieldChange} /></div>}
                                </div>
                                <div style={{ background: "#f1f5f9", borderRadius: 6, padding: "3px 10px", fontSize: "0.75rem", color: "#64748b", fontWeight: 600, flexShrink: 0, marginLeft: 12 }}>
                                    <EditableText value={edu.startDate} path={`education.${ei}.startDate`} onFieldChange={onFieldChange} /> — <EditableText value={edu.endDate} path={`education.${ei}.endDate`} onFieldChange={onFieldChange} />
                                </div>
                            </div>
                        </SortableItem>
                    ))}
                </SortableList>
            </div>
        ),
        skills: cv.skills.length > 0 && (
            <div>
                <ExecSection title="Core Competencies" accent={accent} />
                <div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>
                    {cv.skills.map((skill, i) => (
                        <span key={i} style={{ fontSize: "0.75rem", padding: "4px 12px", background: "#e0f2fe", color: "#0369a1", borderRadius: 20, fontWeight: 500 }}>
                            <EditableText value={skill} path={`skills.${i}`} onFieldChange={onFieldChange} />
                        </span>
                    ))}
                </div>
            </div>
        ),
        languages: cv.languages && cv.languages.length > 0 && (
            <div>
                <ExecSection title="Languages" accent={accent} />
                <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
                    {cv.languages.map((lang, i) => (
                        <span key={i} style={{ fontSize: "0.75rem", padding: "4px 12px", background: "#f1f5f9", color: "#475569", borderRadius: 20, fontWeight: 500 }}>
                            <EditableText value={lang} path={`languages.${i}`} onFieldChange={onFieldChange} />
                        </span>
                    ))}
                </div>
            </div>
        ),
        certifications: cv.certifications && cv.certifications.length > 0 && (
            <div>
                <ExecSection title="Certifications" accent={accent} />
                <ul style={{ paddingLeft: 16, listStyleType: "none" }}>
                    {cv.certifications.map((cert, i) => (
                        <li key={i} style={{ fontSize: "0.8125rem", color: "#475569", lineHeight: 1.6, marginBottom: 4 }}>
                            ✦ <EditableText value={cert} path={`certifications.${i}`} onFieldChange={onFieldChange} />
                        </li>
                    ))}
                </ul>
            </div>
        ),
    };

    const sectionOrderItems = (cv.layout?.sectionOrder || ["summary", "experience", "education", "skills", "languages", "certifications"]).map((id) => {
        if (!sectionComponents[id]) return null;
        return { id };
    }).filter(Boolean) as { id: string }[];

    return (
        <div style={{ fontFamily: "'Inter', sans-serif", color: "#1a1a2e", background: "white" }}>
            {/* Bold Header Bar */}
            {cv.personalInfo.fullName && (
                <div style={{ background: headerBg, color: "white", padding: "32px 40px", marginBottom: 28 }}>
                    <EditableText value={cv.personalInfo.fullName} path="personalInfo.fullName" onFieldChange={onFieldChange} tag="h1"
                        style={{ fontSize: "2.25rem", fontWeight: 900, color: "white", letterSpacing: "-0.04em", marginBottom: 6, display: "block" }} />
                    {cv.personalInfo.title && (
                        <EditableText value={cv.personalInfo.title} path="personalInfo.title" onFieldChange={onFieldChange} tag="div"
                            style={{ fontSize: "1rem", color: accent, fontWeight: 600, marginBottom: 14 }} />
                    )}
                    <div style={{ display: "flex", flexWrap: "wrap", gap: "6px 20px", fontSize: "0.8rem", color: "#94a3b8" }}>
                        {cv.personalInfo.email && <EditableText value={cv.personalInfo.email} path="personalInfo.email" onFieldChange={onFieldChange} style={{ color: "#94a3b8" }} />}
                        {cv.personalInfo.phone && <EditableText value={cv.personalInfo.phone} path="personalInfo.phone" onFieldChange={onFieldChange} style={{ color: "#94a3b8" }} />}
                        {cv.personalInfo.location && <EditableText value={cv.personalInfo.location} path="personalInfo.location" onFieldChange={onFieldChange} style={{ color: "#94a3b8" }} />}
                        {cv.personalInfo.linkedin && <EditableText value={cv.personalInfo.linkedin} path="personalInfo.linkedin" onFieldChange={onFieldChange} style={{ color: "#94a3b8" }} />}
                    </div>
                </div>
            )}

            <div style={{ padding: "0 40px 40px" }}>
                <SortableList
                    items={sectionOrderItems}
                    onReorder={(newOrder: any[]) => {
                        dispatch({ type: "REORDER_SECTIONS", payload: newOrder.map((o: any) => o.id) });
                    }}
                >
                    {sectionOrderItems.map((item) => {
                        if (item.id === "skills" || item.id === "certifications") {
                            // We need to group skills and certifications into a two column layout if they are next to each other
                            // But for simplicity of reordering, we'll keep them as normal blocks here, 
                            // to support drag and drop we can't easily put them side by side in a generic list.
                            // I will keep them stacked for now. User might place them anywhere.
                        }

                        return (
                            <div key={item.id} style={{ marginBottom: (item.id === "skills" || item.id === "languages" || item.id === "certifications") ? 22 : 0 }}>
                                <SortableItem id={item.id}>
                                    {sectionComponents[item.id]}
                                </SortableItem>
                            </div>
                        );
                    })}
                </SortableList>
            </div>
        </div>
    );
}

function ExecSection({ title, accent }: { title: string; accent: string }) {
    return (
        <h2 style={{ fontSize: "0.75rem", fontWeight: 700, textTransform: "uppercase", letterSpacing: "0.12em", color: accent, borderBottom: `1px solid #e2e8f0`, paddingBottom: 6, marginBottom: 12 }}>
            {title}
        </h2>
    );
}

"use client";

import React from "react";
import { CVData } from "@/lib/cv-types";
