                                </div>
                                {edu.gpa && <div style={{ fontSize: "0.8125rem", color: "#9ca3af", marginTop: 2 }}>GPA: <EditableText value={edu.gpa} path={`education.${ei}.gpa`} onFieldChange={onFieldChange} /></div>}
