                                        style={{ fontSize: "0.9375rem", fontWeight: 700, color: "#1a1a2e" }} />
                                    <span style={{ fontSize: "0.72rem", color: "#9ca3af", flexShrink: 0, marginLeft: 8 }}>
                                        <EditableText value={edu.startDate} path={`education.${ei}.startDate`} onFieldChange={onFieldChange} /> — <EditableText value={edu.endDate} path={`education.${ei}.endDate`} onFieldChange={onFieldChange} />
                                    </span>
                                </div>
                                <div style={{ fontSize: "0.8rem", color: accent, fontWeight: 500 }}>
                                    <EditableText value={edu.institution} path={`education.${ei}.institution`} onFieldChange={onFieldChange} />
                                    {edu.location && <span style={{ color: "#9ca3af" }}> · <EditableText value={edu.location} path={`education.${ei}.location`} onFieldChange={onFieldChange} /></span>}
                                </div>
                                {edu.gpa && <div style={{ fontSize: "0.8rem", color: "#9ca3af", marginTop: 2 }}>GPA: <EditableText value={edu.gpa} path={`education.${ei}.gpa`} onFieldChange={onFieldChange} /></div>}
                            </div>
                        </SortableItem>
                    ))}
                </SortableList>
            </div>
        ),
        certifications: cv.certifications && cv.certifications.length > 0 && (
            <div style={{ marginBottom: 24 }}>
                <MainSection title="Certifications" accent={accent} />
                <ul style={{ paddingLeft: 16, listStyleType: "none", margin: 0 }}>
                    {cv.certifications.map((cert, i) => (
                        <li key={i} style={{ fontSize: "0.8rem", color: "#374151", lineHeight: 1.6, position: "relative" }}>
                            <span style={{ position: "absolute", left: -12, color: accent }}>•</span>
                            <EditableText value={cert} path={`certifications.${i}`} onFieldChange={onFieldChange} />
                        </li>
                    ))}
                </ul>
            </div>
        ),
        skills: cv.skills.length > 0 && (
            <div style={{ marginBottom: 20 }}>
                <SbSection title="Skills" accent={accent} />
                <div style={{ display: "flex", flexDirection: "column", gap: 5 }}>
                    {cv.skills.map((skill, i) => (
                        <div key={i} style={{ display: "flex", alignItems: "center", gap: 7 }}>
                            <div style={{ width: 6, height: 6, borderRadius: "50%", background: accent, flexShrink: 0 }} />
                            <EditableText value={skill} path={`skills.${i}`} onFieldChange={onFieldChange}
                                style={{ fontSize: "0.75rem", color: "#e2e8f0" }} />
                        </div>
                    ))}
                </div>
            </div>
        ),
        languages: cv.languages && cv.languages.length > 0 && (
            <div style={{ marginBottom: 20 }}>
                <SbSection title="Languages" accent={accent} />
                <div style={{ display: "flex", flexDirection: "column", gap: 5 }}>
                    {cv.languages.map((lang, i) => (
                        <EditableText key={i} value={lang} path={`languages.${i}`} onFieldChange={onFieldChange}
                            style={{ fontSize: "0.75rem", color: "#94a3b8" }} tag="div" />
                    ))}
                </div>
            </div>
        )
    };

    return (
        <div style={{ display: "flex", flex: 1, minHeight: "100%", fontFamily: "'Inter', sans-serif" }}>
            {/* Sidebar */}
            <div style={{ width: 210, background: sidebarBg, color: "white", padding: "36px 22px", flexShrink: 0 }}>
                {cv.personalInfo.fullName && (
                    <>
                        <EditableText value={cv.personalInfo.fullName} path="personalInfo.fullName" onFieldChange={onFieldChange} tag="h1"
                            style={{ fontSize: "1.25rem", fontWeight: 800, color: "white", marginBottom: 4, display: "block", lineHeight: 1.2 }} />
                        {cv.personalInfo.title && (
                            <EditableText value={cv.personalInfo.title} path="personalInfo.title" onFieldChange={onFieldChange} tag="div"
                                style={{ fontSize: "0.8rem", color: accent, fontWeight: 500, marginBottom: 16 }} />
                        )}
                    </>
                )}

                <SbSection title="Contact" accent={accent} />
                <div style={{ fontSize: "0.75rem", color: "#94a3b8", display: "flex", flexDirection: "column", gap: 5, marginBottom: 24 }}>
                    {cv.personalInfo.email && <EditableText value={cv.personalInfo.email} path="personalInfo.email" onFieldChange={onFieldChange} tag="div" style={{ color: "#94a3b8" }} />}
                    {cv.personalInfo.phone && <EditableText value={cv.personalInfo.phone} path="personalInfo.phone" onFieldChange={onFieldChange} tag="div" style={{ color: "#94a3b8" }} />}
                    {cv.personalInfo.location && <EditableText value={cv.personalInfo.location} path="personalInfo.location" onFieldChange={onFieldChange} tag="div" style={{ color: "#94a3b8" }} />}
                    {cv.personalInfo.linkedin && <EditableText value={cv.personalInfo.linkedin} path="personalInfo.linkedin" onFieldChange={onFieldChange} tag="div" style={{ color: "#94a3b8" }} />}
                </div>

                <SortableList
                    items={sidebarOrderItems}
                    onReorder={(newOrder: any[]) => handleReorder(newOrder, "sidebar")}
                >
                    {sidebarOrderItems.map((item) => (
                        <SortableItem key={item.id} id={item.id}>
                            {sectionComponents[item.id]}
                        </SortableItem>
                    ))}
                </SortableList>
            </div>

            {/* Main */}
            <div style={{ flex: 1, padding: "36px 32px", background: "white", color: "#1a1a2e" }}>
                <SortableList
                    items={mainOrderItems}
                    onReorder={(newOrder: any[]) => handleReorder(newOrder, "main")}
                >
                    {mainOrderItems.map((item) => (
                        <SortableItem key={item.id} id={item.id}>
                            {sectionComponents[item.id]}
                        </SortableItem>
                    ))}
                </SortableList>
            </div>
        </div>
    );
}

function SbSection({ title, accent }: { title: string; accent: string }) {
    return (
        <div style={{ fontSize: "0.65rem", fontWeight: 700, textTransform: "uppercase", letterSpacing: "0.12em", color: accent, marginBottom: 8, borderBottom: `1px solid rgba(16,185,129,0.2)`, paddingBottom: 4 }}>
            {title}
        </div>
    );
}

function MainSection({ title, accent }: { title: string; accent: string }) {
    return (
        <h2 style={{ fontSize: "0.8125rem", fontWeight: 700, textTransform: "uppercase", letterSpacing: "0.1em", color: accent, borderBottom: `2px solid ${accent}`, paddingBottom: 4, marginBottom: 12 }}>
            {title}
        </h2>
    );
}

"use client";

import React from "react";
import { CVData } from "@/lib/cv-types";
import { SortableList } from "../dnd/SortableList";
import { SortableItem } from "../dnd/SortableItem";
import { useCVStore } from "@/lib/cv-store";

export interface TemplateProps {
    cv: CVData;
    onFieldChange: (path: string, value: string) => void;
}

function EditableText({
    value,
    path,
    onFieldChange,
    style,
    tag: Tag = "span",
    placeholder = "...",
}: {
    value: string;
    path: string;
    onFieldChange: (path: string, value: string) => void;
    style?: React.CSSProperties;
    tag?: keyof React.JSX.IntrinsicElements;
    placeholder?: string;
}) {
    return (
        <Tag
            contentEditable
            suppressContentEditableWarning
            data-placeholder={placeholder}
            onBlur={(e) => {
                const el = e.currentTarget as HTMLElement;
                onFieldChange(path, el.innerText.trim());
            }}
            style={{
                outline: "none",
                cursor: "text",
                borderRadius: 3,
                transition: "background 0.15s",
                minWidth: 20,
                ...style,
            }}
            className="editable-field"
        >
            {value}
        </Tag>
    );
}

export default function TechTemplate({ cv, onFieldChange }: TemplateProps) {
    const { dispatch } = useCVStore();
    const accent = cv.layout?.themeColor || "#10b981"; // Emerald

    const sectionComponents: Record<string, React.ReactNode> = {
        summary: cv.summary && (
            <div style={{ marginBottom: 24 }}>
                <SectionHeader title="01_PROFILE" accent={accent} />
                <EditableText
                    value={cv.summary}
                    path="summary"
                    onFieldChange={onFieldChange}
                    tag="p"
                    style={{ fontSize: "0.875rem", color: "#9ca3af", lineHeight: 1.6 }}
                />
            </div>
        ),
        experience: cv.experience.length > 0 && (
            <div style={{ marginBottom: 24 }}>
                <SectionHeader title="02_EXPERIENCE" accent={accent} />
                <SortableList
                    items={cv.experience}
                    onReorder={(newOrder) => {
                        dispatch({ type: "REORDER_LIST", payload: { path: "experience", newOrder } });
                    }}
                >
                    {cv.experience.map((exp, ei) => (
                        <SortableItem key={exp.id} id={exp.id} handleStyle={{ top: 0, left: -28 }}>
                            <div style={{ marginBottom: 20, borderLeft: `1px dashed #374151`, paddingLeft: 16, position: "relative" }}>
                                <div style={{ position: "absolute", left: -4, top: 4, width: 7, height: 7, background: "#111827", border: `1px solid ${accent}` }} />
                                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: 2 }}>
                                    <EditableText value={exp.jobTitle} path={`experience.${ei}.jobTitle`} onFieldChange={onFieldChange} tag="h3"
                                        style={{ fontSize: "0.9375rem", fontWeight: 700, color: "#f3f4f6" }} />
                                    <span style={{ fontSize: "0.75rem", color: accent, flexShrink: 0, marginLeft: 8 }}>
                                        [<EditableText value={exp.startDate} path={`experience.${ei}.startDate`} onFieldChange={onFieldChange} /> - <EditableText value={exp.endDate} path={`experience.${ei}.endDate`} onFieldChange={onFieldChange} />]
                                    </span>
                                </div>
                                <div style={{ fontSize: "0.8125rem", color: "#9ca3af", fontWeight: 600, marginBottom: 8 }}>
                                    <span style={{ color: accent }}>@</span> <EditableText value={exp.company} path={`experience.${ei}.company`} onFieldChange={onFieldChange} />
                                    {exp.location && <span> | <EditableText value={exp.location} path={`experience.${ei}.location`} onFieldChange={onFieldChange} /></span>}
                                </div>
                                {exp.description.length > 0 && (
                                    <ul style={{ paddingLeft: 16, listStyleType: "none", display: "flex", flexDirection: "column", gap: 4 }}>
                                        {exp.description.map((d, di) => (
                                            <li key={di} style={{ fontSize: "0.8125rem", color: "#d1d5db", lineHeight: 1.5 }}>
                                                <span style={{ color: "#4b5563", marginRight: 6 }}>{'>'}</span>
                                                <EditableText value={d} path={`experience.${ei}.description.${di}`} onFieldChange={onFieldChange} />
                                            </li>
                                        ))}
                                    </ul>
                                )}
                            </div>
                        </SortableItem>
                    ))}
                </SortableList>
            </div>
        ),
        education: cv.education.length > 0 && (
            <div style={{ marginBottom: 24 }}>
                <SectionHeader title="03_EDUCATION" accent={accent} />
                <SortableList
                    items={cv.education}
                    onReorder={(newOrder) => {
                        dispatch({ type: "REORDER_LIST", payload: { path: "education", newOrder } });
                    }}
                >
                    {cv.education.map((edu, ei) => (
                        <SortableItem key={edu.id} id={edu.id} handleStyle={{ top: 0, left: -28 }}>
                            <div style={{ marginBottom: 16, borderLeft: `1px dashed #374151`, paddingLeft: 16, position: "relative" }}>
                                <div style={{ position: "absolute", left: -4, top: 4, width: 7, height: 7, background: "#111827", border: `1px solid ${accent}` }} />
                                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: 2 }}>
                                    <EditableText value={edu.degree} path={`education.${ei}.degree`} onFieldChange={onFieldChange} tag="h3"
                                        style={{ fontSize: "0.9375rem", fontWeight: 700, color: "#f3f4f6" }} />
                                    <span style={{ fontSize: "0.75rem", color: accent, flexShrink: 0, marginLeft: 8 }}>
                                        [<EditableText value={edu.startDate} path={`education.${ei}.startDate`} onFieldChange={onFieldChange} /> - <EditableText value={edu.endDate} path={`education.${ei}.endDate`} onFieldChange={onFieldChange} />]
                                    </span>
                                </div>
                                <div style={{ fontSize: "0.8125rem", color: "#9ca3af", fontWeight: 600, marginBottom: 4 }}>
                                    <span style={{ color: accent }}>@</span> <EditableText value={edu.institution} path={`education.${ei}.institution`} onFieldChange={onFieldChange} />
                                    {edu.location && <span> | <EditableText value={edu.location} path={`education.${ei}.location`} onFieldChange={onFieldChange} /></span>}
                                </div>
                                {edu.gpa && <div style={{ fontSize: "0.8125rem", color: "#6b7280" }}>// GPA: <EditableText value={edu.gpa} path={`education.${ei}.gpa`} onFieldChange={onFieldChange} /></div>}
                            </div>
