                        {cv.personalInfo.title && (
                            <div style={{ fontSize: "1rem", color: accent, marginBottom: 16 }}>
                                {'> '}
                                <EditableText
                                    value={cv.personalInfo.title}
                                    path="personalInfo.title"
                                    onFieldChange={onFieldChange}
                                />
