                        )}
                        <div style={{ display: "flex", flexWrap: "wrap", gap: "6px 16px", fontSize: "0.8125rem", color: "#9ca3af" }}>
                            {cv.personalInfo.email && <div>E: <EditableText value={cv.personalInfo.email} path="personalInfo.email" onFieldChange={onFieldChange} /></div>}
                            {cv.personalInfo.phone && <div>P: <EditableText value={cv.personalInfo.phone} path="personalInfo.phone" onFieldChange={onFieldChange} /></div>}
                            {cv.personalInfo.location && <div>L: <EditableText value={cv.personalInfo.location} path="personalInfo.location" onFieldChange={onFieldChange} /></div>}
                            {cv.personalInfo.linkedin && <div>U: <EditableText value={cv.personalInfo.linkedin} path="personalInfo.linkedin" onFieldChange={onFieldChange} /></div>}
                        </div>
                    </div>
                )}

                {/* Sortable Main Sections */}
                <SortableList
                    items={sectionOrderItems}
                    onReorder={(newOrder) => {
                        dispatch({ type: "REORDER_SECTIONS", payload: newOrder.map((o) => o.id) });
                    }}
                >
                    {sectionOrderItems.map((item) => (
                        <SortableItem key={item.id} id={item.id}>
                            {sectionComponents[item.id]}
                        </SortableItem>
                    ))}
                </SortableList>
            </div>
        </div>
    );
}

function SectionHeader({ title, accent }: { title: string; accent: string }) {
    return (
        <div style={{ marginBottom: 16 }}>
            <h2 style={{
                fontSize: "1rem", fontWeight: 700,
                color: accent, margin: 0, paddingBottom: 4
            }}>
                {title} <span style={{ color: "#374151" }}>----------------------------------------------------</span>
            </h2>
        </div>
    );
}

"use client";

import React, { createContext, useContext, useReducer, ReactNode } from "react";
import { CVData, ChatMessage, emptyCVData } from "./cv-types";
import { TemplateId } from "./cv-templates";

interface CVState {
    messages: ChatMessage[];
    cvData: CVData;
    isLoading: boolean;
    templateId: TemplateId;
    cvId: string | null;
}

type CVAction =
    | { type: "ADD_MESSAGE"; payload: ChatMessage }
    | { type: "UPDATE_CV"; payload: Partial<CVData> }
    | { type: "SET_LOADING"; payload: boolean }
    | { type: "SET_TEMPLATE"; payload: TemplateId }
    | { type: "SET_CV_ID"; payload: string | null }
    | { type: "LOAD_CV"; payload: { cvId: string; templateId: TemplateId; data: CVData } }
    | { type: "REORDER_SECTIONS"; payload: string[] }
    | { type: "REORDER_LIST"; payload: { path: keyof CVData; newOrder: any[] } }
    | { type: "SET_THEME_COLOR"; payload: string };

const initialState: CVState = {
    messages: [],
    cvData: { ...emptyCVData },
    isLoading: false,
    templateId: "classic",
    cvId: null,
};

function mergeCV(current: CVData, update: Partial<CVData>): CVData {
    return {
        personalInfo: {
            ...current.personalInfo,
            ...(update.personalInfo || {}),
        },
        summary: update.summary ?? current.summary,
        experience: update.experience ?? current.experience,
        education: update.education ?? current.education,
        skills: update.skills ?? current.skills,
        languages: update.languages ?? current.languages,
        certifications: update.certifications ?? current.certifications,
        layout: update.layout ?? current.layout,
    };
}

function cvReducer(state: CVState, action: CVAction): CVState {
    switch (action.type) {
        case "ADD_MESSAGE":
            return { ...state, messages: [...state.messages, action.payload] };
        case "UPDATE_CV":
            return { ...state, cvData: mergeCV(state.cvData, action.payload) };
        case "SET_LOADING":
            return { ...state, isLoading: action.payload };
        case "SET_TEMPLATE":
            return { ...state, templateId: action.payload };
        case "SET_CV_ID":
            return { ...state, cvId: action.payload };
        case "LOAD_CV":
            return {
                ...state,
                cvId: action.payload.cvId,
                templateId: action.payload.templateId,
                cvData: action.payload.data,
            };
        case "REORDER_SECTIONS":
            return {
                ...state,
                cvData: { ...state.cvData, layout: { ...state.cvData.layout, sectionOrder: action.payload } },
            };
        case "REORDER_LIST":
            return {
                ...state,
                cvData: { ...state.cvData, [action.payload.path]: action.payload.newOrder },
            };
        case "SET_THEME_COLOR":
            return {
                ...state,
                cvData: { ...state.cvData, layout: { ...state.cvData.layout, themeColor: action.payload } },
            };
        default:
            return state;
    }
}

const CVContext = createContext<{
    state: CVState;
    dispatch: React.Dispatch<CVAction>;
} | null>(null);

export function CVProvider({ children }: { children: ReactNode }) {
    const [state, dispatch] = useReducer(cvReducer, initialState);
    return (
        <CVContext.Provider value={{ state, dispatch }}>
            {children}
        </CVContext.Provider>
    );
}

export function useCVStore() {
    const context = useContext(CVContext);
    if (!context) throw new Error("useCVStore must be used within CVProvider");
    return context;
}

import { createServerClient } from '@supabase/ssr'
import { NextResponse, type NextRequest } from 'next/server'

export async function updateSession(request: NextRequest) {
    let supabaseResponse = NextResponse.next({
        request,
    })

    const supabase = createServerClient(
        process.env.NEXT_PUBLIC_SUPABASE_URL!,
        process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
        {
            cookies: {
                getAll() {
                    return request.cookies.getAll()
                },
                setAll(cookiesToSet) {
                    cookiesToSet.forEach(({ name, value, options }) => request.cookies.set(name, value))
                    supabaseResponse = NextResponse.next({
                        request,
                    })
                    cookiesToSet.forEach(({ name, value, options }) =>
                        supabaseResponse.cookies.set(name, value, options)
                    )
                },
            },
        }
    )

    // IMPORTANT: Avoid writing any logic between createServerClient and
    // supabase.auth.getUser(). A simple mistake could make it very hard to debug
    // issues with users being randomly logged out.

    const {
        data: { user },
    } = await supabase.auth.getUser()

    // Protect the /app workspace route
    if (
        !user &&
        request.nextUrl.pathname.startsWith('/app')
    ) {
        const url = request.nextUrl.clone()
        url.pathname = '/login'
        return NextResponse.redirect(url)
    }

    // Redirect logged-in users away from the login page
    if (
        user &&
        request.nextUrl.pathname === '/login'
    ) {
        const url = request.nextUrl.clone()
        url.pathname = '/app'
        return NextResponse.redirect(url)
    }

    return supabaseResponse
}
